-- F01: What is Restorative Reproductive Medicine (RRM)?
INSERT INTO faq (id, faq_code, slug, question, basic_answer, schema_answer, published_answer, category, seo_title, seo_description, sort_order, status) VALUES ('faq_a3dec55ff208a826857f46ee2e9eec5a', 'F01', 'what-is-restorative-reproductive-medicine-rrm', 'What is Restorative Reproductive Medicine (RRM)?', 'Restorative Reproductive Medicine (RRM) treats the root causes of infertility to restore natural fertility and enable natural conception, rather than suppressing symptoms or bypassing the reproductive system through assisted reproductive technologies.', 'Restorative Reproductive Medicine (RRM) is a medical approach that identifies and treats the root causes of infertility and reproductive health conditions to restore natural fertility. RRM focuses on helping couples conceive naturally by addressing underlying conditions rather than bypassing the reproductive system.', '<p class="direct-answer">Restorative Reproductive Medicine (RRM) is a medical approach that diagnoses and treats the root causes of reproductive health conditions, including infertility, endometriosis, PCOS, recurrent miscarriage, pelvic pain, and hormonal disorders, to restore natural function.</p><h3>The Root Cause Approach</h3><p>RRM differs from conventional reproductive medicine by addressing why fertility problems exist rather than suppressing symptoms or bypassing the reproductive system. When couples face infertility, RRM clinicians investigate underlying conditions like endometriosis, PCOS, metabolic dysfunction, or structural abnormalities that may be preventing natural conception.</p><p>This approach recognizes that many reproductive health issues have treatable causes. Rather than moving immediately to assisted reproductive technologies, RRM clinicians focus on restoring the body''s natural reproductive function through targeted medical and surgical interventions.</p><h3>Natural Conception Focus</h3><p>RRM prioritizes helping couples conceive naturally within the woman''s body. This means treating conditions that interfere with ovulation, fertilization, or implantation so that conception can occur through the couple''s own reproductive systems. The goal is fertility restoration, not fertility replacement.</p><h3>Professional Organization and Standards</h3><p>RRM care is delivered by multidisciplinary teams: board-certified OBGYNs, reproductive endocrinologists, and family physicians with additional training in cycle-based evaluation, alongside certified cycle charting instructors, registered nutritionists, and naturopaths.</p><ul class="evidence-list"><li>The International Institute for Restorative Reproductive Medicine (IIRRM) provides professional education and standards</li><li>The STORRM registry tracks outcomes and maintains quality standards for RRM practices</li><li>RRM follows evidence-based protocols while emphasizing individualized care</li></ul><h3>Whole-Person Medical Ethics</h3><p>RRM takes a couple-centered approach that considers both partners in fertility treatment. This includes thorough evaluation of male and female factors, transparent communication about treatment options, and respect for couples'' values and preferences in their reproductive journey.</p><p class="key-takeaway">RRM represents a paradigm shift toward cause-based fertility treatment that restores natural reproductive function rather than bypassing or suppressing it.</p><p class="disclaimer">This information is educational and not a substitute for individualized medical care. Consult an RRM clinician or healthcare provider for guidance specific to your situation.</p>', 'Foundational', 'What is Restorative Reproductive Medicine (RRM)?', 'Learn about Restorative Reproductive Medicine (RRM), a root-cause approach to fertility treatment that restores natural conception rather than bypassing reproduction.', 1, 'published');
INSERT INTO faq_resource (faq_id, title, url, sort_order) VALUES ('faq_a3dec55ff208a826857f46ee2e9eec5a', 'What is RRM — IIRRM', 'https://iirrm.org/what-is-rrm/', 0);
INSERT INTO faq_resource (faq_id, title, url, sort_order) VALUES ('faq_a3dec55ff208a826857f46ee2e9eec5a', 'IIRRM — Iirrm.org', 'https://iirrm.org/', 1);

-- F02: How is RRM different from IVF/IUI‑centered care?
INSERT INTO faq (id, faq_code, slug, question, basic_answer, schema_answer, published_answer, category, seo_title, seo_description, sort_order, status) VALUES ('faq_af9ece0c4b68e0cca08c34c014c09650', 'F02', 'how-is-rrm-different-from-ivf-iui-centered-care', 'How is RRM different from IVF/IUI‑centered care?', 'RRM diagnoses and treats underlying reproductive conditions while IVF/IUI bypass these conditions. RRM uses thorough evaluation, surgical correction when needed, metabolic optimization, and cycle education to restore natural fertility rather than technological intervention.', 'RRM diagnoses and treats underlying reproductive health conditions while ART bypasses these conditions to achieve pregnancy without addressing root causes. RRM focuses on restoring natural reproductive function through thorough evaluation and targeted treatment of specific conditions like endometriosis, PCOS, and male factor issues.', '<p class="direct-answer">RRM diagnoses and treats underlying reproductive health conditions while ART (IVF/IUI) bypasses these conditions to achieve pregnancy without addressing root causes.</p>

<h3>Fundamental Approach Differences</h3>
<p>Restorative Reproductive Medicine operates on a diagnose-and-treat model. RRM clinicians identify specific conditions like endometriosis, PCOS, or male factor issues, then create treatment protocols to restore natural reproductive function. ART-centered care bypasses underlying conditions to achieve pregnancy through technological intervention.</p>

<p>Couples often arrive at RRM clinics after being told their only option is IVF, when they actually have diagnosable, treatable conditions. In ART-centered care, treatment plans are frequently shaped by what insurance covers or what couples can afford, rather than by specific medical need.</p>

<h3>RRM Diagnostic and Treatment Components</h3>
<p>RRM typically includes thorough diagnostic evaluation, surgical correction when indicated (such as endometriosis excision), nutritional and metabolic optimization, cycle timing education, and ongoing monitoring. The focus is measurable progress toward reproductive health restoration rather than immediate pregnancy achievement.</p>

<p>This couple-centered approach addresses both partners'' health, as male factor is the sole cause in about 20% of infertile couples and a contributing factor in another 30 to 40%.</p>

<ul class="evidence-list">
<li>Endometriosis affects 10-15% of reproductive-age women but is often undiagnosed or mismanaged with suppressive medications</li>
<li>PCOS diagnosis requires specific metabolic evaluation beyond basic hormone panels</li>
<li>Male factor evaluation should include assessment beyond basic semen analysis</li>
<li>Nutritional deficiencies commonly impact reproductive function in both men and women</li>
</ul>

<h3>A Different Model, Not a Stepping Stone</h3>
<p>RRM is not a first step before IVF. It is a fundamentally different approach to reproductive medicine. The goal is not to prepare couples for assisted reproduction. The goal is to restore natural reproductive function so that conception happens in the body, between the couple, without laboratory intervention.</p>

<p>This distinction matters. When reproductive health is genuinely restored through RRM, couples conceive naturally and do not need laboratory assistance for subsequent pregnancies. Their underlying health conditions are treated, not just bypassed. The conventional model frames the body as broken and positions technology as the solution. RRM restores the body''s own capacity.</p>

<p class="key-takeaway">RRM prioritizes reproductive health restoration through root cause treatment, offering couples the opportunity to conceive naturally while addressing underlying conditions that affect long-term health.</p>

<p class="disclaimer">This information is educational and not a substitute for individualized medical care. Consult an RRM clinician or healthcare provider for guidance specific to your situation.</p>', 'Foundational', 'RRM vs IVF: Root Cause Treatment vs Bypass Approach', 'Learn how Restorative Reproductive Medicine differs from IVF/IUI by diagnosing and treating underlying conditions rather than bypassing them for pregnancy.', 2, 'published');
INSERT INTO faq_resource (faq_id, title, url, sort_order) VALUES ('faq_af9ece0c4b68e0cca08c34c014c09650', 'What is RRM — IIRRM', 'https://iirrm.org/what-is-rrm/', 0);
INSERT INTO faq_resource (faq_id, title, url, sort_order) VALUES ('faq_af9ece0c4b68e0cca08c34c014c09650', 'IIRRM — Iirrm.org', 'https://iirrm.org/about/', 1);

-- F03: What conditions does RRM address?
INSERT INTO faq (id, faq_code, slug, question, basic_answer, schema_answer, published_answer, category, seo_title, seo_description, sort_order, status) VALUES ('faq_4a36bdaefadd1218afff51b4c59153c9', 'F03', 'what-conditions-does-rrm-address', 'What conditions does RRM address?', 'RRM addresses endometriosis, PCOS, thyroid disorders, luteal dysfunction, recurrent miscarriage, male factor infertility, fibroids, polyps, and chronic endometritis through individualized cause-based treatment protocols that restore natural reproductive function.', 'RRM addresses root causes of infertility including endometriosis, PCOS, thyroid dysfunction, luteal phase defects, recurrent pregnancy loss, male factor issues, fibroids, polyps, and chronic endometritis. Each couple receives individualized protocol blocks targeting their specific combination of reproductive health conditions.', '<p class="direct-answer">RRM addresses the root causes of reproductive health conditions including endometriosis, PCOS, unexplained infertility, thyroid dysfunction, luteal phase defects, recurrent pregnancy loss, male factor issues, ovulatory dysfunction, pelvic pain, PMS/PMDD, and perimenopause through individualized cause-based protocols.</p>

<h3>Primary Conditions Treated</h3>
<p>Restorative Reproductive Medicine takes a cause-based approach to fertility challenges. RRM clinicians address the underlying reproductive health issues that prevent natural conception rather than bypassing them.</p>

<p>Common conditions addressed in RRM practice include:</p>
<ul>
<li><strong>Endometriosis and adenomyosis:</strong> surgical excision and adhesion prevention protocols</li>
<li><strong>PCOS and anovulation:</strong> cycle restoration and metabolic optimization</li>
<li><strong>Thyroid disorders:</strong> addressing both hypo- and hyperthyroid conditions affecting fertility</li>
<li><strong>Luteal phase dysfunction:</strong> correcting progesterone deficiency and cycle timing issues</li>
<li><strong>Recurrent pregnancy loss:</strong> investigating and treating underlying causes</li>
<li><strong>Male factor infertility:</strong> optimizing sperm parameters through targeted interventions</li>
<li><strong>Uterine fibroids and polyps:</strong> surgical removal when affecting fertility</li>
<li><strong>Chronic endometritis:</strong> antibiotic protocols for uterine inflammation</li>
<li><strong>Unexplained infertility:</strong> reframed as undiagnosed, not unexplained, with systematic evaluation to identify the cause</li>
<li><strong>Pelvic pain and irregular periods:</strong> diagnostic workup to find the cause, not just manage symptoms</li>
<li><strong>PMS / PMDD:</strong> hormonal evaluation with cycle-timed testing and targeted support</li>
<li><strong>Perimenopause:</strong> cycle-charted hormonal transition monitoring and individualized support</li>
</ul>

<h3>Evidence Foundation</h3>
<ul class="evidence-list">
<li>Endometriosis excision shows superior outcomes to ablation for fertility restoration (Adamson & Pasta, 2010)</li>
<li>PCOS responds to targeted metabolic interventions including cycle-timed nutrition protocols</li>
<li>Thyroid optimization within narrow fertility ranges improves conception rates</li>
<li>Chronic endometritis treatment may improve outcomes in select populations, particularly those with recurrent implantation failure or recurrent pregnancy loss</li>
</ul>

<h3>RRM Approach</h3>
<p>RRM''s distinguishing commitment is treating the actual condition rather than working around it. Suppressive medications and technological bypasses address neither the cause nor the disease progression. RRM restores normal reproductive function wherever possible.</p>

<p>Each couple receives individualized protocol blocks targeting their specific combination of issues. Both partners are included because fertility involves two people. Treatment timing follows natural cycle physiology rather than artificial timelines.</p>

<p class="key-takeaway">RRM''s cause-based approach treats endometriosis, PCOS, thyroid dysfunction, luteal defects, pregnancy loss, male factor issues, fibroids, polyps, and chronic endometritis through individualized fertility restoration protocols.</p>

<p class="disclaimer">This information is educational and not a substitute for individualized medical care. Consult an RRM clinician or healthcare provider for guidance specific to your situation.</p>', 'Foundational', 'What Conditions Does RRM Address? | Fertility Causes Treated', 'RRM treats endometriosis, PCOS, thyroid issues, luteal dysfunction, pregnancy loss, male factor, fibroids, polyps & chronic endometritis with cause-based protocols.', 3, 'published');
INSERT INTO faq_resource (faq_id, title, url, sort_order) VALUES ('faq_4a36bdaefadd1218afff51b4c59153c9', 'What is RRM — IIRRM', 'https://iirrm.org/what-is-rrm/', 0);
