-- F04: What is NaProTECHNOLOGY and the Creighton Model (CrMS)?
INSERT INTO faq (id, faq_code, slug, question, basic_answer, schema_answer, published_answer, category, seo_title, seo_description, sort_order, status) VALUES ('faq_919f7f0ace5ad5466a94743ccfed691d', 'F04', 'what-is-naprotechnology-and-the-creighton-model-crms', 'What is NaProTECHNOLOGY and the Creighton Model (CrMS)?', 'NaProTECHNOLOGY is a medical approach using natural fertility cycles to diagnose and treat reproductive disorders. It relies on the Creighton Model charting system to track biomarkers like cervical mucus patterns, which reveal hormonal function and cycle health for targeted treatment timing.', 'NaProTECHNOLOGY is a medical approach that works with natural fertility cycles to diagnose and treat reproductive disorders using the Creighton Model FertilityCare System for biomarker tracking. The standardized charting method tracks cervical mucus patterns and other fertility signs to identify root causes and time treatments with natural cycles.', '<p class="direct-answer">NaProTECHNOLOGY (Natural Procreative Technology) is a medical approach that works with natural fertility cycles to diagnose and treat reproductive disorders, using the Creighton Model FertilityCare System (CrMS) as its foundation for precise biomarker tracking.</p>

<p>The Creighton Model FertilityCare System is a standardized charting method that tracks specific fertility biomarkers, primarily cervical mucus patterns, bleeding, and other observable signs. Unlike basic fertility awareness methods, CrMS requires formal instruction from certified practitioners and follows rigorous protocols for accurate data collection.</p>

<p>CrMS charting creates a detailed record of each woman''s unique cycle patterns. These biomarkers reveal hormonal function, ovulation quality, and potential reproductive health issues. The standardized approach means the data can be interpreted consistently by trained clinicians worldwide.</p>

<p>NaProTECHNOLOGY uses this charting data to guide both diagnosis and treatment timing. Instead of suppressing natural cycles, clinicians identify the root causes of cycle irregularities and treat them while preserving reproductive function. Treatment protocols are timed to work with the body''s natural rhythms rather than against them.</p>

<ul class="evidence-list">
<li>CrMS instruction follows standardized protocols developed at the Creighton University Model FertilityCare System</li>
<li>Research shows CrMS can identify luteal phase defects, ovulation disorders, and hormonal imbalances through biomarker patterns</li>
<li>NaProTECHNOLOGY protocols are taught at centers worldwide, including the Pope Paul VI Institute</li>
</ul>

<h3>RRM Integration</h3>
<p>RRM Academy supports CrMS principles within the broader Restorative Reproductive Medicine framework. RRM clinicians use cycle charting data alongside advanced diagnostics and surgical interventions. This combination allows clinicians to address both functional and structural causes of infertility while maintaining the couple-centered, cause-based philosophy that defines restorative care.</p>

<p class="key-takeaway">NaProTECHNOLOGY represents a paradigm shift from symptom suppression to root cause treatment, using precise biomarker tracking to restore natural reproductive function in couples.</p>

<p class="disclaimer">This information is educational and not a substitute for individualized medical care. Consult an RRM clinician or healthcare provider for guidance specific to your situation.</p>', 'Foundational', 'What is NaProTECHNOLOGY & Creighton Model Charting?', 'Learn how NaProTECHNOLOGY uses Creighton Model charting to track fertility biomarkers, diagnose reproductive disorders, and time treatments with natural cycles.', 4, 'published');
INSERT INTO faq_resource (faq_id, title, url, sort_order) VALUES ('faq_919f7f0ace5ad5466a94743ccfed691d', 'FertilityCare — Creighton model system', 'https://www.fertilitycare.org/creighton-model-system/', 0);
INSERT INTO faq_resource (faq_id, title, url, sort_order) VALUES ('faq_919f7f0ace5ad5466a94743ccfed691d', 'Creighton Model FertilityCare — Creightonmodel.com', 'https://creightonmodel.com/', 1);
INSERT INTO faq_resource (faq_id, title, url, sort_order) VALUES ('faq_919f7f0ace5ad5466a94743ccfed691d', 'NaProTECHNOLOGY — Naprotechnology.com', 'https://naprotechnology.com/', 2);

-- F05: What does "natural conception" mean in RRM?
INSERT INTO faq (id, faq_code, slug, question, basic_answer, schema_answer, published_answer, category, seo_title, seo_description, sort_order, status) VALUES ('faq_9f615e8fe5956c3bdbbca93c1b5266d6', 'F05', 'what-does-natural-conception-mean-in-rrm', 'What does "natural conception" mean in RRM?', 'Natural conception in RRM means conception through intercourse within a woman''s reproductive system, rather than in a laboratory. RRM focuses on restoring couples'' natural reproductive function to achieve this by treating underlying causes that prevent the natural process.', 'Natural conception in RRM means conception that occurs through intercourse within a woman''s reproductive system, as opposed to laboratory fertilization. RRM works to restore couples'' natural reproductive function so they can conceive through intercourse by treating underlying causes.', '<p class="direct-answer">Natural conception in RRM means conception that occurs through intercourse within a woman''s reproductive system, as opposed to in vitro fertilization where conception happens in a laboratory.</p>

<p>Restorative Reproductive Medicine centers on restoring couples'' natural reproductive function so they can conceive through intercourse. This approach recognizes that the human reproductive system is designed for natural conception and focuses on identifying and treating the underlying causes that prevent this natural process.</p>

<p>When reproductive function is restored properly, couples can achieve conception during intercourse without requiring laboratory intervention. The embryo develops naturally within the woman''s reproductive tract from the moment of conception, following the body''s biological process.</p>

<h3>How This Shapes RRM Treatment</h3>

<p>The goal of natural conception fundamentally changes how RRM clinicians approach fertility care. Instead of bypassing reproductive problems with assisted reproductive technology, RRM practitioners diagnose and treat the root causes preventing natural conception.</p>

<ul class="evidence-list">
<li>RRM uses detailed diagnostic protocols to identify specific barriers to natural conception</li>
<li>Treatment protocols target underlying conditions like endometriosis, PCOS, and male factor issues</li>
<li>Cycle-timed therapies work with natural reproductive rhythms rather than replacing them</li>
<li>Success is measured by restoration of normal reproductive function, not just pregnancy rates</li>
</ul>

<h3>The RRM Difference</h3>

<p>Conventional fertility medicine often moves quickly to assisted reproductive technologies. RRM prioritizes restoring the body''s natural conception ability first. This approach addresses the underlying reproductive health issues that affect both partners, creating optimal conditions for natural conception.</p>

<p>Achieving natural conception often requires treating multiple systems, including hormonal, metabolic, inflammatory, and structural, to restore full reproductive health in both partners.</p>

<p class="key-takeaway">Natural conception represents RRM''s commitment to fertility restoration through addressing root causes rather than bypassing reproductive function through laboratory intervention.</p>

<p class="disclaimer">This information is educational and not a substitute for individualized medical care. Consult an RRM clinician or healthcare provider for guidance specific to your situation.</p>', 'Foundational', 'What Is Natural Conception in Restorative Medicine?', 'Learn what natural conception means in RRM and how this approach focuses on restoring reproductive function so couples can conceive without laboratory intervention.', 5, 'published');
INSERT INTO faq_resource (faq_id, title, url, sort_order) VALUES ('faq_9f615e8fe5956c3bdbbca93c1b5266d6', 'What is RRM — IIRRM', 'https://iirrm.org/what-is-rrm/', 0);

-- F06: Is RRM evidence‑based? (key trials, registries, and guidelin
INSERT INTO faq (id, faq_code, slug, question, basic_answer, schema_answer, published_answer, category, seo_title, seo_description, sort_order, status) VALUES ('faq_aae1f456fe2b0cfc2fe1669729c6dc4c', 'F06', 'is-rrm-evidence-based-key-trials-registries-and-guidelines', 'Is RRM evidence‑based? (key trials, registries, and guidelines)', 'RRM is evidence-based through peer-reviewed studies including Stanford 2008, Tham 2012, Boyle 2025, and Sanchez-Mendez 2025, plus ongoing iNEST registry data collection. RRM clinicians follow established clinical guidelines while focusing on root cause treatment.', 'RRM is evidence-based through peer-reviewed outcome studies including Stanford 2008, Tham 2012, Boyle 2025, and the Sanchez-Mendez 2025 cohort (n=1,310), plus ongoing data collection through the iNEST registry. RRM clinicians follow established medical guidelines for PCOS, recurrent pregnancy loss, and endometriosis while focusing on addressing underlying causes.', '<p class="direct-answer">RRM is evidence-based through peer-reviewed outcome studies including Stanford et al. (2008), Tham et al. (2012), Boyle et al. (2025), and the largest cohort to date, Sanchez-Mendez et al. (2025, n=1,310), plus ongoing data collection through the iNEST registry.</p><h3>Published Outcome Data</h3><p>The evidence base for Restorative Reproductive Medicine spans over 15 years of peer-reviewed publications. Stanford et al. (2008) established initial outcome data for NaProTechnology in an Irish general practice, reporting a crude live birth rate of 25.5% and an adjusted cumulative rate of 52.8%. Tham et al. (2012) replicated these findings in a Canadian family practice with a 38% crude live birth rate. Boyle et al. (2025) published the first head-to-head RRM-versus-IVF comparison, reporting a 41% live birth rate in 187 couples. Sanchez-Mendez et al. (2025) published the largest cohort to date: 1,310 couples with a crude take-home baby rate of 35.3% and an adjusted cumulative rate of 62.1%.</p><p>The iNEST registry (International NaProTechnology Evaluation STudy), published in HROpen (2022), collects multi-center real-world data from RRM practices. This registry approach allows for ongoing evaluation of protocols and refinement of treatment approaches based on measurable outcomes.</p><h3>Clinical Guidelines Integration</h3><p>RRM clinicians follow established medical guidelines for conditions like PCOS, recurrent pregnancy loss, and endometriosis. The difference lies in the approach. Where conventional guidelines often recommend suppressive medications or immediate ART, RRM protocols first address underlying pathophysiology. For example, PCOS guidelines recommend metformin and lifestyle modifications. RRM expands this to include detailed hormonal assessment, cycle tracking, and targeted nutritional protocols.</p><ul class="evidence-list"><li>Stanford et al. (2008): 25.5% crude, 52.8% adjusted live birth rate (n=1,072, Irish general practice)</li><li>Tham et al. (2012): 38% crude live birth rate (n=108, Canadian family practice)</li><li>Boyle et al. (2025): 41% live birth rate, first RRM-vs-IVF comparison (n=187)</li><li>Sanchez-Mendez et al. (2025): 35.3% crude, 62.1% adjusted take-home baby rate (n=1,310)</li><li>iNEST registry (HROpen 2022): Multi-center real-world data collection</li></ul><h3>The RRM Evidence Approach</h3><p>RRM evidence collection emphasizes long-term reproductive health outcomes rather than single-cycle success rates. This includes tracking live birth rates, pregnancy loss reduction, and cycle health improvement over time. The focus on cause-based treatment means measuring not just conception, but resolution of underlying conditions like luteal phase defects, ovulatory dysfunction, and inflammatory processes.</p><p>RRM protocols undergo continuous refinement based on patient outcomes documented through registries like iNEST. This allows for protocol adjustments based on what works best for specific patient populations and conditions.</p><p class="key-takeaway">RRM combines peer-reviewed outcome studies with continuous registry data collection and established clinical guidelines to provide evidence-based reproductive care focused on addressing root causes rather than bypassing them.</p><p class="disclaimer">This information is educational and not a substitute for individualized medical care. Consult an RRM clinician or healthcare provider for guidance specific to your situation.</p>', 'Foundational', 'Is RRM Evidence-Based? Studies, Registries & Guidelines', 'RRM is evidence-based through Stanford studies, International NPT Evaluation 2022, STORRM registry data, and integration with clinical guidelines for PCOS and RPL.', 6, 'published');
INSERT INTO faq_resource (faq_id, title, url, sort_order) VALUES ('faq_aae1f456fe2b0cfc2fe1669729c6dc4c', 'BMC Pregnancy & Childbirth — S12884 021 03946 8', 'https://bmcpregnancychildbirth.biomedcentral.com/articles/10.1186/s12884-021-03946-8', 0);
