-- F08: Which labs, imaging, and cycle tracking does RRM use?
INSERT INTO faq (id, faq_code, slug, question, basic_answer, schema_answer, published_answer, category, seo_title, seo_description, sort_order, status) VALUES ('faq_da9c89e213321a925886b9b55533b232', 'F08', 'which-labs-imaging-and-cycle-tracking-does-rrm-use', 'Which labs, imaging, and cycle tracking does RRM use?', 'RRM uses CrMS cycle charting with Peak-referenced hormone testing (Peak+3/5/7/9/11), follicle ultrasound series, HSG/SIS imaging, and WHO 6th edition semen analysis. All testing timing is individualized based on each couple''s observed cycle patterns rather than standardized schedules.', 'RRM uses CrMS cycle charting, luteal hormone profiles at Peak+3/+5/+7/+9/+11, follicle ultrasound series, HSG/SIS imaging, and WHO 6th edition semen analysis. All diagnostic timing is individualized based on each couple''s observed cycle patterns for improved accuracy.', '<p class="direct-answer">RRM uses CrMS cycle charting, luteal hormone profiles (Peak+3/+5/+7/+9/+11), follicle ultrasound series, HSG/SIS imaging, and WHO 6th edition semen analysis with individualized timing based on each couple''s patterns.</p><h3>Cycle Tracking Foundation</h3><p>The Creighton Model System (CrMS) is the most widely used cycle tracking method in RRM practice. This standardized method teaches couples to observe and record biological markers of fertility and reproductive health throughout each cycle. Unlike apps or calendar-based predictions, CrMS relies on daily observations of cervical fluid patterns that reflect hormonal changes in real time.</p><p>This body literacy approach provides precise timing for all diagnostic testing and treatment protocols. Couples identify their unique Peak day (the last day of the most fertile-type mucus), which becomes the reference point for all hormone testing and cycle-timed interventions.</p><h3>Hormone Testing Protocol</h3><p>RRM measures hormones at specific cycle days relative to Peak: Peak+3, Peak+5, Peak+7, Peak+9, and Peak+11. This luteal hormone profile captures the complete picture of progesterone production and estrogen patterns throughout the post-ovulatory phase. Traditional cycle day testing (like "day 21" progesterone) often misses the actual luteal phase in couples with irregular cycles.</p><p>The Peak-referenced timing ensures accurate measurement regardless of cycle length variability. This precision reveals luteal phase defects, inadequate corpus luteum function, and other hormone imbalances that affect both conception and pregnancy maintenance.</p><ul class="evidence-list"><li>CrMS has demonstrated 99.5% effectiveness in identifying fertile and infertile phases when taught properly</li><li>Peak-referenced hormone testing provides more accurate luteal assessment than fixed cycle day testing</li><li>WHO 6th edition semen analysis standards improve diagnostic accuracy over previous versions</li></ul><h3>Imaging and Male Factor Assessment</h3><p>Follicle ultrasound series track follicular development from early cycle through ovulation confirmation. This real-time monitoring identifies ovulatory dysfunction, follicle quality issues, and optimal timing for cycle-timed protocols. HSG (hysterosalpingography) and SIS (saline infusion sonography) evaluate uterine anatomy and fallopian tube patency.</p><p>Male partners receive detailed semen analysis following WHO 6th edition standards, which provide updated reference ranges and improved assessment criteria. This analysis examines concentration, motility, morphology, and other parameters that affect conception rates.</p><h3>RRM''s Individualized Approach</h3><p>Every diagnostic protocol adjusts to each couple''s unique cycle patterns and presenting concerns. Rather than standardized testing schedules, RRM clinicians time each assessment based on the couple''s actual biological rhythms observed through cycle charting. This individualized timing improves diagnostic accuracy and treatment effectiveness.</p><p>The integration of cycle awareness, precise hormone measurement, and targeted imaging creates a full fertility assessment that guides cause-based treatment decisions. Couples actively participate in data collection, developing body literacy skills that support long-term reproductive health.</p><p class="key-takeaway">RRM''s diagnostic approach combines standardized CrMS cycle charting with Peak-referenced hormone testing, follicle ultrasound monitoring, anatomical imaging, and WHO-standard semen analysis for a thorough fertility assessment.</p><p class="disclaimer">This information is educational and not a substitute for individualized medical care. Consult an RRM clinician or healthcare provider for guidance specific to your situation.</p>', 'Foundational', 'RRM Lab Tests: CrMS Charting & Peak-Referenced Hormones', 'RRM uses CrMS cycle charting with Peak-referenced hormone testing, follicle ultrasounds, HSG/SIS imaging, and WHO semen analysis for comprehensive assessment.', 8, 'published');
INSERT INTO faq_resource (faq_id, title, url, sort_order) VALUES ('faq_da9c89e213321a925886b9b55533b232', 'FertilityCare — Creighton model system', 'https://www.fertilitycare.org/creighton-model-system/', 0);
INSERT INTO faq_resource (faq_id, title, url, sort_order) VALUES ('faq_da9c89e213321a925886b9b55533b232', 'WHO — 9789240030787', 'https://www.who.int/publications/i/item/9789240030787', 1);
INSERT INTO faq_resource (faq_id, title, url, sort_order) VALUES ('faq_da9c89e213321a925886b9b55533b232', 'NaProTECHNOLOGY — Naprotechnology.com', 'https://naprotechnology.com/', 2);

-- F09: What should I expect at a first RRM consult?
INSERT INTO faq (id, faq_code, slug, question, basic_answer, schema_answer, published_answer, category, seo_title, seo_description, sort_order, status) VALUES ('faq_5fb14ebb8502eb3524cd38aa9cfa6be0', 'F09', 'what-should-i-expect-at-a-first-rrm-consult', 'What should I expect at a first RRM consult?', 'A first RRM consult includes thorough history for both partners, symptom mapping, fertility charting introduction, targeted diagnostic planning, and collaborative goal-setting with potential referrals to specialists.', 'A first RRM consult includes thorough history intake for both partners, an introduction to fertility charting, development of a targeted diagnostic plan, and collaborative goal-setting. The appointment establishes a foundation for cause-based reproductive medicine through thorough assessment and education.', '<p class="direct-answer">A first RRM consult typically includes thorough history intake for both partners, an introduction to fertility charting, development of a targeted diagnostic plan, and collaborative goal-setting for the reproductive health journey.</p>

<h3>Thorough History and Assessment</h3>
<p>The consultation begins with detailed intake for both partners. The RRM clinician reviews medical history, current symptoms, previous testing, and any treatments already tried. This couple-centered approach recognizes that reproductive health involves both partners, even when one partner''s symptoms seem more obvious.</p>

<p>Symptom mapping is a key component. Rather than dismissing symptoms as "normal" or unrelated, the clinician connects patterns between menstrual irregularities, pain, digestive issues, skin changes, and other signs the body may be signaling. This creates a fuller picture of reproductive health status.</p>

<h3>Introduction to Body Literacy</h3>
<p>Couples receive an introduction to fertility charting and cycle tracking. This is not simply about timing intercourse. Charting helps couples understand the body''s signals and provides objective data for the care team. The clinician explains what to observe and how this information guides treatment decisions.</p>

<h3>Diagnostic Planning</h3>
<p>Based on history and symptoms, the clinician develops a targeted plan for labs and imaging. This may include hormone panels timed to specific cycle phases, inflammatory markers, metabolic assessments, or specialized imaging to evaluate structural concerns.</p>

<ul class="evidence-list">
<li>RRM protocol blocks address specific diagnostic categories based on individual presentation</li>
<li>Cycle-timed testing provides more accurate hormonal assessment than random timing</li>
<li>Thorough male evaluation is standard, not optional</li>
</ul>

<h3>Collaborative Goal-Setting</h3>
<p>The first visit establishes shared goals through informed consent discussions. The clinician explains what RRM can and cannot address, realistic timelines for different interventions, and how the specific situation influences treatment approach. This transparency supports informed decision-making.</p>

<p>Referral pathways are discussed when relevant, including referral to an RRM educator for intensive charting support, to a surgeon trained in excisional techniques for endometriosis, or to specialized andrology for male factor evaluation.</p>

<p class="key-takeaway">The first RRM consult establishes a foundation for cause-based reproductive medicine through thorough assessment, education in body literacy, and collaborative treatment planning for both partners.</p>

<p class="disclaimer">This information is educational and not a substitute for individualized medical care. Consult an RRM clinician or healthcare provider for guidance specific to your situation.</p>', 'Foundational', 'What to Expect at Your First RRM Consultation', 'Learn what happens during your first Restorative Reproductive Medicine consult: comprehensive assessment, charting intro, diagnostic planning, and goal-setting.', 9, 'published');
INSERT INTO faq_resource (faq_id, title, url, sort_order) VALUES ('faq_5fb14ebb8502eb3524cd38aa9cfa6be0', 'What is RRM — IIRRM', 'https://iirrm.org/what-is-rrm/', 0);

-- F10: How does RRM handle male‑factor evaluation (Restorative Andr
INSERT INTO faq (id, faq_code, slug, question, basic_answer, schema_answer, published_answer, category, seo_title, seo_description, sort_order, status) VALUES ('faq_3ed329314bd1b94e7bf87a21a74fb6bc', 'F10', 'how-does-rrm-handle-male-factor-evaluation-restorative-andrology', 'How does RRM handle male‑factor evaluation (Restorative Andrology)?', 'RRM provides thorough male evaluation including semen analysis, hormonal assessment, and treatment of underlying causes like varicoceles, infections, and endocrine imbalances as an integral part of couple-centered fertility care.', 'RRM provides thorough Restorative Andrology evaluation and treatment, addressing male reproductive health as an integral part of couple-centered fertility care. Treatment targets root causes including hormonal imbalances, varicoceles, infections, and lifestyle factors that impact sperm production and function.', '<p class="direct-answer">RRM provides thorough Restorative Andrology evaluation and treatment, addressing male reproductive health as an integral part of couple-centered fertility care rather than an afterthought.</p><h3>Thorough Male Evaluation</h3><p>Male-factor evaluation begins with detailed semen analysis and a thorough health assessment. RRM clinicians examine sperm count, motility, morphology, and DNA fragmentation. Beyond basic parameters, the evaluation investigates underlying causes including hormonal imbalances, varicoceles, infections, and metabolic factors that impact sperm production and function.</p><p>The evaluation also screens for health risks that affect both fertility and long-term wellness. Men with fertility challenges face increased risks for cardiovascular disease, diabetes, and other conditions. Early identification allows for preventive intervention.</p><h3>Targeted Treatment Approaches</h3><p>Treatment targets the root causes identified during evaluation. Endocrine optimization addresses hormonal imbalances affecting sperm production. Varicocele repair improves blood flow and reduces oxidative stress. Infection treatment eliminates bacterial or inflammatory causes of poor sperm quality.</p><p>Lifestyle interventions focus on nutrition, exercise, sleep optimization, and toxin reduction. These evidence-based approaches can significantly improve sperm parameters within 2-3 months, the typical sperm production cycle.</p><ul class="evidence-list"><li>Varicocele repair improves sperm concentration and motility in 60-80% of cases</li><li>Antioxidant therapy reduces sperm DNA fragmentation by 13-30%</li><li>Weight optimization can improve testosterone levels and sperm quality</li><li>Infection treatment resolves inflammatory markers affecting sperm function</li></ul><h3>RRM Difference</h3><p>RRM coordinates male and female care simultaneously rather than treating them separately. RRM clinicians work closely with specialized urologists and andrologists when surgical intervention is needed. This coordinated approach ensures both partners receive appropriate evaluation and treatment.</p><p>Male reproductive health affects pregnancy outcomes, not just conception rates. Sperm quality influences embryo development, miscarriage rates, and long-term child health outcomes.</p><p class="key-takeaway">Restorative Andrology addresses male reproductive health as essential to couple fertility through thorough evaluation, root-cause treatment, and coordinated care with specialized providers.</p><p class="disclaimer">This information is educational and not a substitute for individualized medical care. Consult an RRM clinician or healthcare provider for guidance specific to your situation.</p>', 'Foundational', 'RRM Male Factor Evaluation | Restorative Andrology', 'Learn how RRM addresses male fertility through comprehensive Restorative Andrology evaluation, targeting root causes like varicoceles, hormones, and infections.', 10, 'published');
INSERT INTO faq_resource (faq_id, title, url, sort_order) VALUES ('faq_3ed329314bd1b94e7bf87a21a74fb6bc', 'What is RRM — IIRRM', 'https://iirrm.org/what-is-rrm/', 0);
INSERT INTO faq_resource (faq_id, title, url, sort_order) VALUES ('faq_3ed329314bd1b94e7bf87a21a74fb6bc', 'WHO — 9789240030787', 'https://www.who.int/publications/i/item/9789240030787', 1);

-- F11: Where does progesterone fit in early pregnancy support?
INSERT INTO faq (id, faq_code, slug, question, basic_answer, schema_answer, published_answer, category, seo_title, seo_description, sort_order, status) VALUES ('faq_7dde416dd8d0f0cc0c88d913708b6421', 'F11', 'where-does-progesterone-fit-in-early-pregnancy-support', 'Where does progesterone fit in early pregnancy support?', 'Progesterone reduces miscarriage risk in women with prior losses or early bleeding, based on PRISM trial evidence. RRM clinicians use individualized monitoring rather than routine supplementation.', 'Progesterone can reduce miscarriage risk in early pregnancy for women with a history of recurrent losses or early bleeding. The PRISM trial showed significant benefit in these specific groups but no benefit for women without these risk factors.', '<p class="direct-answer">Progesterone can reduce miscarriage risk in early pregnancy for women with a history of recurrent losses or early bleeding, based on individualized monitoring and dosing within restorative care.</p>

<p>Progesterone plays a crucial role in maintaining early pregnancy by supporting the uterine lining and creating optimal conditions for implantation and early fetal development. Not all women need progesterone supplementation. The approach must be individualized based on specific risk factors and clinical presentation.</p>

<h3>Evidence for Progesterone in Threatened Miscarriage</h3>

<p>The PRISM trial provides the strongest evidence for when progesterone helps prevent miscarriage. This large randomized controlled trial found that progesterone significantly reduces miscarriage risk in two specific groups: women with a history of one or more prior losses and women experiencing early pregnancy bleeding. For women with both risk factors, the benefit was even more pronounced.</p>

<ul class="evidence-list">
<li>PRISM trial (Coomarasamy et al., 2019): Progesterone reduced miscarriage risk by 3-5% in women with prior losses and early bleeding</li>
<li>Women with 1+ previous losses showed significant benefit from progesterone supplementation</li>
<li>Early pregnancy bleeding combined with loss history showed the greatest protective effect</li>
<li>No benefit demonstrated in women without these specific risk factors</li>
</ul>

<h3>RRM Approach to Progesterone Support</h3>

<p>Within Restorative Reproductive Medicine, progesterone support is part of thorough early pregnancy monitoring rather than routine supplementation. RRM clinicians identify couples who would specifically benefit from luteal support based on individual risk profile, cycle patterns, and previous pregnancy outcomes.</p>

<p>The RRM approach emphasizes precise timing and dosing based on natural cycle cooperation. Rather than standard protocols, clinicians monitor individual progesterone levels and adjust support accordingly. This allows targeted intervention for couples who need it while avoiding unnecessary medication for those who don''t.</p>

<p class="key-takeaway">Progesterone supplementation in early pregnancy is most appropriate for women with specific risk factors like prior losses and early bleeding, not as routine treatment for all women.</p>

<p class="disclaimer">This information is educational and not a substitute for individualized medical care. Consult an RRM clinician or healthcare provider for guidance specific to your situation.</p>', 'Foundational', 'Progesterone in Early Pregnancy: When It Helps Prevent Loss', 'Evidence-based guide to progesterone support in early pregnancy. Learn when progesterone helps prevent miscarriage and RRM''s individualized approach.', 11, 'published');
INSERT INTO faq_resource (faq_id, title, url, sort_order) VALUES ('faq_7dde416dd8d0f0cc0c88d913708b6421', 'Miscarriage Association UK — The prism trial', 'https://www.miscarriageassociation.org.uk/research/the-prism-trial/', 0);
INSERT INTO faq_resource (faq_id, title, url, sort_order) VALUES ('faq_7dde416dd8d0f0cc0c88d913708b6421', 'NEJM — NEJMoa1813730', 'https://www.nejm.org/doi/full/10.1056/NEJMoa1813730', 1);
-- MANUAL RESOLUTION NEEDED: faq_library_ref for F11 -> article slug="a-randomized-trial-of-progesterone-in-women-with-bleeding-in-early-pregnancy-rec7mjvhhkr2ttyqe" (Coomarasamy A et al., 2019)
-- INSERT INTO faq_library_ref (faq_id, article_id, sort_order) VALUES ('faq_7dde416dd8d0f0cc0c88d913708b6421', '<resolve article_id for slug: a-randomized-trial-of-progesterone-in-women-with-bleeding-in-early-pregnancy-rec7mjvhhkr2ttyqe>', 0);

-- F12: What’s RRM’s stance on thyroid and fertility?
INSERT INTO faq (id, faq_code, slug, question, basic_answer, schema_answer, published_answer, category, seo_title, seo_description, sort_order, status) VALUES ('faq_8147317e8afdc6d81d46ef73815b8bbb', 'F12', 'what-s-rrm-s-stance-on-thyroid-and-fertility', 'What’s RRM’s stance on thyroid and fertility?', 'RRM screens for thyroid disease in fertility patients using individualized treatment thresholds. Evidence from TABLET and T4LIFE trials shows no fertility benefit from routine levothyroxine in TPO-positive patients with normal thyroid function.', 'RRM screens for both overt and subclinical thyroid disease in fertility patients, using individualized thresholds rather than routine levothyroxine treatment for all TPO-positive euthyroid patients. This evidence-based approach follows recent trials showing no fertility benefit from automatic levothyroxine treatment in women with thyroid antibodies but normal thyroid function.', '<p class="direct-answer">RRM screens for both overt and subclinical thyroid disease in fertility patients, using individualized thresholds rather than routine levothyroxine treatment for all TPO-positive euthyroid patients.</p>

<p>Thyroid function affects fertility in multiple ways. It influences ovulation, cycle regularity, and pregnancy outcomes. Many fertility clinics automatically prescribe levothyroxine for any thyroid antibodies or borderline TSH levels. RRM clinicians take a more precise approach.</p>

<p>Thyroid screening in RRM practice covers overt thyroid disease and subclinical hypothyroidism. When thyroid peroxidase (TPO) antibodies appear in women with normal thyroid function, clinicians evaluate each case individually. The decision to treat depends on specific clinical factors, not just the presence of antibodies.</p>

<ul class="evidence-list">
<li>The TABLET trial (2019) showed no fertility benefit from routine levothyroxine in euthyroid women with thyroid antibodies</li>
<li>The T4LIFE study confirmed no improvement in live birth rates with levothyroxine treatment in TPO-positive euthyroid women</li>
<li>Current guidelines recommend individualized TSH thresholds for preconception and pregnancy care</li>
</ul>

<h3>RRM''s Approach to Thyroid and Fertility</h3>
<p>Evidence-based guidelines recognize thyroid treatment is not one-size-fits-all. For couples trying to conceive, RRM clinicians consider TSH levels, antibody status, clinical symptoms, and individual risk factors. During pregnancy, thresholds are adjusted based on trimester and clinical presentation.</p>

<p>This individualized approach prevents unnecessary medication while ensuring appropriate treatment for couples who truly need it. Thyroid function is monitored throughout treatment cycles, with protocols adjusted based on measurable progress.</p>

<p class="key-takeaway">RRM uses evidence-based thyroid screening with individualized treatment thresholds rather than automatic levothyroxine prescribing for all TPO-positive patients.</p>

<p class="disclaimer">This information is educational and not a substitute for individualized medical care. Consult an RRM clinician or healthcare provider for guidance specific to your situation.</p>', 'Foundational', 'RRM''s Evidence-Based Approach to Thyroid & Fertility', 'Learn RRM''s individualized thyroid screening approach for fertility patients. Evidence-based treatment thresholds, not automatic levothyroxine for TPO-positive cases.', 12, 'published');
INSERT INTO faq_resource (faq_id, title, url, sort_order) VALUES ('faq_8147317e8afdc6d81d46ef73815b8bbb', 'NEJM — NEJMoa1812537', 'https://www.nejm.org/doi/full/10.1056/NEJMoa1812537', 0);
INSERT INTO faq_resource (faq_id, title, url, sort_order) VALUES ('faq_8147317e8afdc6d81d46ef73815b8bbb', 'Source — ScienceDirect', 'https://www.sciencedirect.com/science/article/abs/pii/S2213858722000456', 1);

-- F13: Is letrozole first‑line for anovulatory PCOS in RRM?
INSERT INTO faq (id, faq_code, slug, question, basic_answer, schema_answer, published_answer, category, seo_title, seo_description, sort_order, status) VALUES ('faq_eba938529458e3bbf8ba9d94f2e4c4c7', 'F13', 'is-letrozole-first-line-for-anovulatory-pcos-in-rrm', 'Is letrozole first‑line for anovulatory PCOS in RRM?', 'Yes, letrozole is first-line for anovulatory PCOS per international guidelines. RRM combines letrozole with metabolic optimization for root cause treatment. Letrozole has better ovulation rates and lower twin risk than clomiphene citrate.', 'Yes, letrozole is first-line treatment for ovulation induction in anovulatory PCOS according to international guidelines. RRM protocols include thorough metabolic optimization alongside letrozole therapy to address root causes of PCOS.', '<p class="direct-answer">Yes, letrozole is first-line treatment for ovulation induction in anovulatory PCOS according to international guidelines, and RRM protocols include thorough metabolic optimization alongside letrozole therapy.</p>

<h3>Letrozole as First-Line Treatment</h3>
<p>The International Evidence-Based Guideline for PCOS establishes letrozole as the preferred first-line ovulation induction agent for women with anovulatory PCOS. Published data consistently shows letrozole outperforming clomiphene citrate in both ovulation rates and live birth outcomes for PCOS patients.</p>

<p>Letrozole offers several advantages over older treatments. It has a shorter half-life, reducing the risk of multiple follicle development and twins. The medication works by temporarily blocking estrogen production, which releases the natural feedback inhibition on FSH release. This leads to more physiologic follicle development compared to the estrogen receptor blocking action of clomiphene citrate.</p>

<h3>RRM''s Approach</h3>
<p>While letrozole addresses ovulation, RRM protocols simultaneously target the root metabolic dysfunction driving PCOS. Clinicians combine letrozole with specific lifestyle modifications, targeted nutritional support, and metabolic optimization strategies. This approach addresses insulin resistance, inflammation, and hormonal imbalances that maintain the anovulatory state.</p>

<p>Couples receive detailed cycle monitoring to track ovulation response and adjust dosing as needed. Body literacy skills allow recognition of fertile signs and appropriate cycle timing. This cycle-timed approach maximizes the effectiveness of restored ovulation.</p>

<ul class="evidence-list">
<li>International PCOS Guidelines recommend letrozole as first-line ovulation induction</li>
<li>Legro et al. (2014) demonstrated superior live birth rates with letrozole vs. clomiphene</li>
<li>Lower twin rate with letrozole: 3.4% vs. 7.4% with clomiphene citrate</li>
<li>Shorter half-life reduces cumulative effects and side effects</li>
</ul>

<h3>Safety and Monitoring</h3>
<p>Letrozole has an excellent safety profile with minimal side effects. The most common include mild hot flashes and fatigue, which resolve quickly due to the short half-life. Unlike clomiphene, letrozole does not have anti-estrogenic effects on the endometrium or cervical mucus, maintaining optimal conditions for conception.</p>

<p class="key-takeaway">Letrozole combined with metabolic optimization provides PCOS couples with evidence-based ovulation induction while addressing underlying reproductive health dysfunction.</p>

<p class="disclaimer">This information is educational and not a substitute for individualized medical care. Consult an RRM clinician or healthcare provider for guidance specific to your situation.</p>', 'Foundational', 'Is Letrozole First-Line for PCOS Ovulation Induction?', 'Learn why letrozole is first-line treatment for anovulatory PCOS per international guidelines, plus how RRM combines it with metabolic optimization.', 13, 'published');
INSERT INTO faq_resource (faq_id, title, url, sort_order) VALUES ('faq_eba938529458e3bbf8ba9d94f2e4c4c7', 'Source — ScienceDirect', 'https://www.sciencedirect.com/science/article/pii/S0015028223007197', 0);
INSERT INTO faq_resource (faq_id, title, url, sort_order) VALUES ('faq_eba938529458e3bbf8ba9d94f2e4c4c7', 'Recommendations from the 2023 international evidence based guideline for the ass — ASRM', 'https://www.asrm.org/practice-guidance/practice-committee-documents/recommendations-from-the-2023-international-evidence-based-guideline-for-the-assessment-and-management-of-polycystic-ovary-syndrome/', 1);
-- MANUAL RESOLUTION NEEDED: faq_library_ref for F13 -> article slug="letrozole-or-clomiphene-for-infertility-in-the-polycystic-ovary-syndrome-recgrvvtlvs9dogjt" (Legro RS et al., 2014)
-- INSERT INTO faq_library_ref (faq_id, article_id, sort_order) VALUES ('faq_eba938529458e3bbf8ba9d94f2e4c4c7', '<resolve article_id for slug: letrozole-or-clomiphene-for-infertility-in-the-polycystic-ovary-syndrome-recgrvvtlvs9dogjt>', 0);

-- F14: Do I need to be Catholic to use Creighton/NaPro or see an RR
INSERT INTO faq (id, faq_code, slug, question, basic_answer, schema_answer, published_answer, category, seo_title, seo_description, sort_order, status) VALUES ('faq_607a18d1b6dd755f6cd350accd62bafd', 'F14', 'do-i-need-to-be-catholic-to-use-creighton-napro-or-see-an-rrm-clinician', 'Do I need to be Catholic to use Creighton/NaPro or see an RRM clinician?', 'No religious requirement exists for Creighton Model, NaPro, or RRM care. These are evidence-based medical systems available to people of all faiths and backgrounds. Many secular health systems teach these methods. RRM focuses on medical education and treatment while respecting personal values in reproductive decisions.', 'No, religious affiliation is not required to use the Creighton Model, NaProTechnology, or see an RRM clinician. These are evidence-based medical systems available to people of all faiths and backgrounds, with many secular health institutions now offering these services.', '<p class="direct-answer">No. The Creighton Model FertilityCare System, NaProTechnology, and RRM are evidence-based medical systems available to people of all faiths and backgrounds.</p>

<p>The Creighton Model is a standardized fertility awareness method developed through decades of scientific research. While it originated within Catholic healthcare institutions, the system itself is based on objective biological markers that work the same way regardless of religious beliefs. Many secular health systems, universities, and independent practices now teach CrMS and offer NaProTechnology services.</p>

<p>RRM clinics serve patients from diverse religious backgrounds, including those who identify as secular, Protestant, Jewish, Muslim, and others. The focus is on understanding reproductive health through cycle charting and addressing underlying conditions through medical treatment. Personal values guide how individuals apply this knowledge.</p>

<ul class="evidence-list">
<li>The Creighton Model was developed at Creighton University through standardized research protocols and is taught at secular institutions</li>
<li>Studies on CrMS effectiveness include participants regardless of religious affiliation</li>
<li>Many non-Catholic health systems integrate fertility awareness methods into their reproductive health services</li>
</ul>

<h3>RRM Approach to Inclusivity</h3>
<p>RRM clinicians focus on medical education and treatment options rather than prescriptive family planning guidance. Thorough information about reproductive health allows couples to make informed decisions aligned with their own values. This includes discussing available contraceptive options, fertility treatments, and family planning approaches during care.</p>

<p>The clinical protocols for diagnosing and treating conditions like endometriosis, PCOS, or recurrent pregnancy loss are the same regardless of background. How individuals choose to apply this knowledge in their reproductive decisions varies by person.</p>

<p class="key-takeaway">RRM provides evidence-based reproductive healthcare through fertility awareness and restorative treatments accessible to couples of all backgrounds who want to understand and optimize their reproductive health.</p>

<p class="disclaimer">This information is educational and not a substitute for individualized medical care. Consult an RRM clinician or healthcare provider for guidance specific to your situation.</p>', 'Foundational', 'Do I Need to Be Catholic for Creighton/NaPro/RRM Care?', 'No religious requirement for Creighton Model, NaPro, or RRM care. Evidence-based fertility awareness and reproductive medicine available to all backgrounds.', 14, 'published');
INSERT INTO faq_resource (faq_id, title, url, sort_order) VALUES ('faq_607a18d1b6dd755f6cd350accd62bafd', 'CHS Buffalo — Natural family planning', 'https://www.chsbuffalo.org/services/natural-family-planning/faqs/', 0);
INSERT INTO faq_resource (faq_id, title, url, sort_order) VALUES ('faq_607a18d1b6dd755f6cd350accd62bafd', 'OSF Healthcare — Creighton model', 'https://www.osfhealthcare.org/services/specialties/women/programs-services/fertility-care/creighton-model', 1);

-- F15: How do I get started or find an RRM clinician/educator near 
INSERT INTO faq (id, faq_code, slug, question, basic_answer, schema_answer, published_answer, category, seo_title, seo_description, sort_order, status) VALUES ('faq_5f0ad54c84e7117930c55c0e152aff59', 'F15', 'how-do-i-get-started-or-find-an-rrm-clinician-educator-near-me', 'How do I get started or find an RRM clinician/educator near me?', 'Find an RRM clinician through the IIRRM provider directory or FertilityCare physician directory. Creighton Model teachers provide cycle charting training that supports medical treatment. Many practitioners offer telehealth options.', 'To find an RRM clinician, use the International Institute of Restorative Reproductive Medicine provider directory or locate a FertilityCare center through their physician directory. Many RRM practitioners also offer virtual consultations to expand access beyond geographic limitations.', '<p class="direct-answer">To find an RRM clinician, start with the IIRRM provider directory, Natural Womanhood''s searchable directory, or the instructor networks for your charting method: FertilityCare Centers of America (Creighton), Marquette Method Professionals Association, or FEMM Health.</p><h3>Getting Connected to RRM Care</h3><p>The IIRRM provider directory is the primary referral network for RRM-trained physicians. Natural Womanhood maintains a searchable directory of providers and charting instructors. Each charting method also has its own instructor network: FertilityCare Centers of America for Creighton Model, the Marquette Method Professionals Association, and FEMM Health for FEMM providers.</p><p>Many patients begin by learning a cycle charting method. Charting builds body literacy and produces the diagnostic data that RRM clinicians need. A diagnosis is not required to start charting. Beginning charting before the first RRM consultation gives the clinician actionable data from day one.</p><h3>Creighton Model Teachers and Support</h3><p>Creighton Model FertilityCare teachers help couples learn cycle charting and body literacy skills that support RRM protocols. The Creighton teacher locator lists certified instructors by area. This foundational training often runs parallel to medical treatment and provides essential cycle-timed data for the clinician.</p><h3>Virtual Care Options</h3><p>Many RRM practitioners offer telehealth consultations, expanding access beyond geographic limitations. Virtual appointments work well for initial consultations, protocol adjustments, and ongoing monitoring when combined with local lab work and imaging.</p><p>Before the first appointment, it helps to prepare questions about insurance coverage, treatment timelines, and financial considerations. RRM often requires different insurance navigation than conventional fertility treatments.</p><p class="key-takeaway">RRM care combines specialized medical training with cycle-based protocols, requiring practitioners specifically trained in restorative reproductive medicine approaches.</p><p class="disclaimer">This information is educational and not a substitute for individualized medical care. Consult an RRM clinician or healthcare provider for guidance specific to your situation.</p>', 'Foundational', 'How to Find an RRM Clinician Near You | RRM Academy', 'Find a Restorative Reproductive Medicine clinician through IIRRM referrals, FertilityCare directories, or telehealth options. Get connected to cause-based care.', 15, 'published');
INSERT INTO faq_resource (faq_id, title, url, sort_order) VALUES ('faq_5f0ad54c84e7117930c55c0e152aff59', 'RRM Referral Request — IIRRM', 'https://iirrm.org/rrm-referral-request/', 0);
INSERT INTO faq_resource (faq_id, title, url, sort_order) VALUES ('faq_5f0ad54c84e7117930c55c0e152aff59', 'FertilityCare — Find a center', 'https://www.fertilitycare.org/find-a-center/', 1);
INSERT INTO faq_resource (faq_id, title, url, sort_order) VALUES ('faq_5f0ad54c84e7117930c55c0e152aff59', 'Creighton Model FertilityCare — Teacherlocation', 'https://creightonmodel.com/teacherlocation/', 2);

-- F16: How much does RRM or NaProTechnology treatment cost compared
INSERT INTO faq (id, faq_code, slug, question, basic_answer, schema_answer, published_answer, category, seo_title, seo_description, sort_order, status) VALUES ('faq_db04da09208bef8b03d3da8dc9575f39', 'F16', 'how-much-does-rrm-or-naprotechnology-treatment-cost-compared-to-ivf', 'How much does RRM or NaProTechnology treatment cost compared to IVF?', 'RRM costs vary by diagnosis, but many components are covered by standard health insurance because RRM treats diagnosed medical conditions using standard billing codes. IVF costs $15,000 to $30,000 per cycle, with most couples spending $40,000 to $60,000 total. A prospective cohort study found IVF costs 20 times more than medication-based fertility treatments.', 'RRM costs vary by diagnosis and treatment plan, but many components are covered by standard health insurance because RRM uses standard diagnostic and treatment codes for diagnosed medical conditions. IVF costs $15,000 to $30,000 per cycle in the United States, with most couples spending $40,000 to $60,000 total. A prospective cohort study found IVF costs on average 20 times more than medication-based fertility treatments.', '<p class="direct-answer">RRM costs vary by diagnosis and treatment plan. The key structural advantage is that RRM treats diagnosed medical conditions using standard diagnostic and treatment codes, so many components are covered by standard health insurance. IVF costs $15,000 to $30,000 per cycle, with most couples spending $40,000 to $60,000 total. A prospective cohort study found IVF costs on average 20 times more than medication-based fertility treatments (Katz et al., 2011).</p>

<p>The cost difference reflects fundamentally different approaches. RRM diagnoses and treats underlying reproductive conditions. IVF bypasses them. RRM treatment addresses the cause once. IVF must be repeated for each desired pregnancy without treating the underlying health condition.</p>

<h3>Why RRM Is Often More Affordable</h3>
<p>RRM uses standard medical procedures billed with standard CPT codes. Charting instruction, hormonal panels, medications, and surgery for conditions like endometriosis or PCOS use the same codes any specialist would bill. This means many components of RRM care are covered by standard health insurance without requiring a separate "fertility treatment" benefit.</p>

<p>By contrast, IVF is typically classified as elective fertility treatment and covered by insurance in only a minority of U.S. states. Most couples pay out of pocket.</p>

<h3>IVF Cost Reality</h3>
<p>IVF costs $15,000 to $30,000 per cycle in the United States, including medications and monitoring. Most couples need two to three cycles to achieve a live birth, bringing average total spending to $40,000 to $60,000. Costs rise with add-ons like genetic testing (PGT-A), ICSI, and frozen embryo transfers. HFEA data shows an average live birth rate of approximately 33% per embryo transferred for women under 35, declining significantly with age.</p>

<h3>Insurance and Legislative Progress</h3>
<ul class="evidence-list">
<li>Many RRM treatments are covered because they are coded as treatment for diagnosed medical conditions, not as "fertility treatment"</li>
<li>Endometriosis surgery, thyroid treatment, and PCOS management all use standard medical billing codes</li>
<li>In 2025, Arkansas became the first state to mandate insurance coverage for restorative reproductive medicine</li>
<li>The RESTORE Act (H.R. 3589) seeks to expand federal access to RRM as an alternative to IVF-only coverage mandates</li>
</ul>

<h3>Questions to Ask Your Insurer</h3>
<p>Ask whether cycle-timed hormonal testing is covered for a diagnosed condition such as PCOS or endometriosis. Ask whether laparoscopic excision surgery is covered as a gynecologic procedure separate from any fertility benefit. Ask about out-of-network benefits if the RRM physician is not in-network.</p>

<p class="key-takeaway">RRM''s cause-based approach treats diagnosed medical conditions using standard billing codes. Many components are covered by standard health insurance. IVF is typically classified as elective and costs 20 times more than medication-based fertility treatments.</p>

<p class="disclaimer">This information is educational and not a substitute for individualized medical care. Consult an RRM clinician or healthcare provider for guidance specific to your situation.</p>', 'Foundational', 'RRM vs IVF Cost: Treatment Comparison & Value Analysis', 'Compare RRM and IVF costs. RRM treats diagnosed conditions with standard insurance codes. IVF costs 20x more than medication-based fertility treatments.', 16, 'published');

-- F17: Does insurance cover NaProTechnology or RRM treatment?
INSERT INTO faq (id, faq_code, slug, question, basic_answer, schema_answer, published_answer, category, seo_title, seo_description, sort_order, status) VALUES ('faq_05a3787fcb6a02e2cea3b1446c8f3210', 'F17', 'does-insurance-cover-naprotechnology-or-rrm-treatment', 'Does insurance cover NaProTechnology or RRM treatment?', 'Most insurance plans provide partial coverage for RRM diagnostic testing and surgical procedures, but coverage varies by plan. Diagnostic work and surgical treatments typically qualify for standard reproductive health benefits.', 'Most insurance plans provide partial coverage for RRM diagnostic testing and surgical procedures, though coverage varies significantly by plan. Diagnostic procedures and surgical treatments typically qualify for standard reproductive health benefits.', '<p class="direct-answer">Many RRM treatments are covered by standard health insurance because they treat diagnosed medical conditions using conventional billing codes. Arkansas became the first state to mandate coverage for restorative reproductive medicine in 2025, and the federal RESTORE Act (H.R. 3589) has been introduced to expand access further.</p>

<h3>Understanding Insurance Coverage for RRM</h3>
<p>Insurance coverage for Restorative Reproductive Medicine follows standard medical billing practices. Diagnostic procedures like hormone testing, ultrasounds, and laparoscopic surgery typically receive coverage when medically indicated. The key distinction is that RRM uses these established procedures to identify and treat root causes rather than suppress symptoms.</p>

<p>Coverage challenges often arise with fertility monitoring instruction and cycle tracking education, which insurance may classify as educational rather than medical services. The underlying diagnostic work and surgical treatments generally qualify for coverage under standard reproductive health benefits.</p>

<h3>What Is Typically Covered</h3>
<ul class="evidence-list">
<li>Hormone panels and endocrine testing when clinically indicated</li>
<li>Pelvic ultrasounds and diagnostic imaging</li>
<li>Laparoscopic surgery for endometriosis excision or adhesion removal</li>
<li>Treatment of underlying conditions like PCOS or thyroid disorders</li>
<li>Follow-up medical consultations and monitoring</li>
</ul>

<h3>RRM''s Transparent Approach</h3>
<p>RRM clinics prioritize transparent pricing and work directly with patients to clarify coverage options before treatment begins. This differs significantly from fertility clinics that often require couples to navigate complex package pricing without clear coverage information upfront.</p>

<p>The focus on treating diagnosable medical conditions rather than bypassing them means many RRM interventions qualify for medical coverage that fertility treatments might not receive. Root cause treatment often proves more cost-effective long-term than repeated ART cycles.</p>

<h3>Policy Developments</h3><p>In 2025, Arkansas became the first U.S. state to mandate insurance coverage for restorative reproductive medicine through the RESTORE Act (Act 859). The federal RESTORE Act (H.R. 3589) has been introduced in Congress to expand access nationally. These developments reflect growing recognition that RRM treats specific medical conditions and should qualify for standard medical coverage.</p><p class="key-takeaway">Many RRM treatments qualify for standard medical billing codes. Arkansas now mandates RRM coverage, and federal legislation has been introduced to expand access.</p>

<p class="disclaimer">This information is educational and not a substitute for individualized medical care. Consult an RRM clinician or healthcare provider for guidance specific to your situation.</p>', 'Foundational', 'Does Insurance Cover NaProTechnology & RRM Treatment?', 'Learn about insurance coverage for Restorative Reproductive Medicine. Most plans cover diagnostic testing and surgical procedures under standard benefits.', 17, 'published');

-- F18: How long does RRM treatment typically take before pregnancy?
INSERT INTO faq (id, faq_code, slug, question, basic_answer, schema_answer, published_answer, category, seo_title, seo_description, sort_order, status) VALUES ('faq_449cc2eb12096e189540e2be94a84b04', 'F18', 'how-long-does-rrm-treatment-typically-take-before-pregnancy', 'How long does RRM treatment typically take before pregnancy?', 'RRM treatment typically takes 6-18 months for fertility restoration, varying based on individual conditions, age, and treatment complexity. Timeline depends on addressing root causes rather than working around dysfunction.', 'RRM treatment typically takes 6-18 months for fertility restoration, depending on individual conditions and root causes. Unlike conventional fertility treatments, RRM addresses underlying dysfunction which may take longer initially but provides sustainable reproductive health improvements.', '<p class="direct-answer">RRM treatment timeline varies by diagnosis, typically ranging from 3 to 18 months depending on complexity. In Boyle et al. (2025), the mean time from starting RRM treatment to conception was 12 months.</p>

<h3>Understanding RRM Treatment Phases</h3>
<p>Restorative Reproductive Medicine works through distinct phases rather than a fixed timeline. The diagnostic phase typically takes several months, as cycle charting and thorough hormone evaluation require multiple tracked cycles. Treatment implementation follows, addressing specific conditions like endometriosis excision, metabolic optimization, or cycle restoration.</p>

<p>Each couple''s timeline depends on their unique presentation. A woman with PCOS may see cycle restoration within 3-6 months, while someone requiring endometriosis excision might need 6-12 months for full healing before optimal fertility returns. Men with reproductive health issues typically see improvements in 3-4 months, aligning with the sperm production cycle.</p>

<h3>Factors Affecting Timeline</h3>
<p>Several factors influence treatment duration. Age affects healing capacity and response time. Severity of underlying conditions determines protocol complexity. Previous suppressive medications may require extended restoration periods. Couple compliance with lifestyle modifications and protocol adherence significantly impacts progress speed.</p>

<p>Unlike conventional fertility treatments that work around dysfunction, RRM addresses root causes. Initial treatment may take longer, but couples often achieve sustained fertility restoration rather than temporary intervention.</p>

<h3>RRM Approach to Timeline Expectations</h3>
<p>RRM clinicians provide individualized timeline estimates based on thorough assessment. Progress is measured through objective markers like cycle quality, hormone optimization, and symptom resolution rather than just pregnancy achievement. Many couples report improved overall health during treatment, regardless of conception timing.</p>

<p>Treatment protocols include regular monitoring and adjustment. If progress stalls, clinicians investigate additional factors or modify approaches. This responsive methodology often prevents extended treatment periods common in conventional fertility care.</p>

<p class="key-takeaway">RRM treatment timeline varies from 3 to 18 months depending on diagnosis and complexity. In published data, mean time to conception was 12 months. RRM offers sustainable reproductive health improvements beyond pregnancy achievement.</p>

<p class="disclaimer">This information is educational and not a substitute for individualized medical care. Consult an RRM clinician or healthcare provider for guidance specific to your situation.</p>', 'Foundational', 'How Long Does RRM Treatment Take? Timeline & Expectations', 'RRM treatment typically takes 6-18 months for fertility restoration. Learn about treatment phases, factors affecting timeline, and what to expect during care.', 18, 'published');
-- MANUAL RESOLUTION NEEDED: faq_library_ref for F18 -> article slug="understanding-restorative-reproductive-medicine-recu1z1xulr6qtn2a" (Boyle P, 2025)
-- INSERT INTO faq_library_ref (faq_id, article_id, sort_order) VALUES ('faq_449cc2eb12096e189540e2be94a84b04', '<resolve article_id for slug: understanding-restorative-reproductive-medicine-recu1z1xulr6qtn2a>', 0);

-- F20: What are the success rates for NaProTechnology and RRM?
INSERT INTO faq (id, faq_code, slug, question, basic_answer, schema_answer, published_answer, category, seo_title, seo_description, sort_order, status) VALUES ('faq_c4607d2d53e5cf3c22fb0a7e64b5f150', 'F20', 'what-are-the-success-rates-for-naprotechnology-and-rrm', 'What are the success rates for NaProTechnology and RRM?', 'RRM success rates vary by condition, showing crude live birth rates of 26-41% and adjusted cumulative rates of 50-62% in published studies. Success includes symptom resolution, cycle normalization, and natural conception rather than just pregnancy rates per procedure.', 'RRM success rates vary by condition and couple-specific factors, with published studies showing crude live birth rates of 26-41% and adjusted cumulative rates of 50-62%. Success in RRM measures thorough reproductive health restoration including symptom resolution, cycle normalization, and natural conception outcomes.', '<p class="direct-answer">RRM success rates vary by condition and couple-specific factors, with published studies showing crude live birth rates of 26 to 41% and adjusted cumulative rates of 50 to 62%, while measuring both reproductive restoration and overall health outcomes.</p>

<p>Success in Restorative Reproductive Medicine means more than pregnancy rates. RRM clinicians track multiple outcomes: symptom resolution, cycle normalization, hormonal balance restoration, and conception rates for couples seeking pregnancy. This approach differs from ART facilities that primarily report live birth rates per procedure.</p>

<p>Published research on NaProTechnology protocols shows variable results by condition. Sanchez-Mendez et al. (2025) studied 1,310 couples and reported a crude take-home baby rate of 35.3% and an adjusted cumulative rate of 62.1%, varying by age (83.7% for ages 18-30, 53.3% for ages 36-40). Boyle et al. (2025) reported a 41% crude live birth rate in 187 couples at NeoFertility Dublin, with a mean time to conception of 12 months. These numbers reflect couples who achieved pregnancy naturally after RRM treatment, not through assisted reproductive technology.</p>

<ul class="evidence-list">
<li>Stanford et al. (2008): 25.5% crude, 52.8% adjusted live birth rate (n=1,072, Irish general practice)</li>
<li>Tham et al. (2012): 38% crude live birth rate (n=108, Canadian family practice)</li>
<li>Boyle et al. (2025): 41% crude live birth rate (n=187, first RRM-vs-IVF comparison)</li>
<li>Sanchez-Mendez et al. (2025): 35.3% crude, 62.1% adjusted take-home baby rate (n=1,310)</li>
</ul>

<h3>What RRM Measures Differently</h3>
<p>RRM success extends beyond conception rates to include cycle regularity, pain reduction, energy improvement, and halting disease progression. Couples often report significant quality of life improvements even when pregnancy is not the primary goal. The cause-based approach means addressing root reproductive dysfunction, not just bypassing it.</p>

<p>Individual success depends on multiple factors: age, specific diagnosis, treatment compliance, male factor involvement, and how long conditions went undiagnosed. RRM clinicians provide personalized prognosis based on thorough evaluation, not population averages.</p>

<p class="key-takeaway">RRM success rates reflect thorough reproductive health restoration, measured through multiple outcomes including natural conception rates, symptom resolution, and cycle normalization for each couple''s specific situation.</p>

<p class="disclaimer">This information is educational and not a substitute for individualized medical care. Consult an RRM clinician or healthcare provider for guidance specific to your situation.</p>', 'Foundational', 'RRM & NaProTechnology Success Rates: What to Expect', 'RRM success rates range from 20-76% for natural conception depending on condition and treatment. Learn how RRM measures comprehensive reproductive restoration.', 20, 'published');
-- MANUAL RESOLUTION NEEDED: faq_library_ref for F20 -> article slug="understanding-restorative-reproductive-medicine-recu1z1xulr6qtn2a" (Boyle P, 2025)
